Here’s an example of refactoring a function that calculates the total price of an order with multiple items, applying discounts and taxes. The original function is monolithic and hard to maintain; the refactored version breaks it into smaller, reusable, and testable functions:

python
# Original: Monolithic and hard to maintain
def calculate_total(items, discount_rate, tax_rate):
    total = 0
    for item in items:
        total += item['price'] * item['quantity']
    total *= (1 - discount_rate)
    total *= (1 + tax_rate)
    return round(total, 2)

# Refactored: Modular and maintainable
from typing import List, Dict

def calculate_subtotal(items: List[Dict]) -> float:
    """Calculate the sum of all item prices times quantities."""
    return sum(item['price'] * item['quantity'] for item in items)

def apply_discount(subtotal: float, discount_rate: float) -> float:
    """Apply discount to the subtotal."""
    return subtotal * (1 - discount_rate)

def apply_tax(subtotal_after_discount: float, tax_rate: float) -> float:
    """Apply tax to the discounted subtotal."""
    return subtotal_after_discount * (1 + tax_rate)

def calculate_total(items, discount_rate, tax_rate) -> float:
    """Calculate the final total after discount and tax."""
    subtotal = calculate_subtotal(items)
    discounted = apply_discount(subtotal, discount_rate)
    total = apply_tax(discounted, tax_rate)
    return round(total, 2)


This refactoring improves readability, testability, and maintainability by separating concerns and making the logic reusable.
